class Solution:
    def countNicePairs(self, nums):
        MOD = 10 ** 9 + 7
        def rev(x):
            return int(str(x)[::-1])
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                if nums[i] + rev(nums[j]) == nums[j] + rev(nums[i]):
                    count += 1
        return count % MOD

solutions.javascript:
var countNicePairs = function(nums) {
    const MOD = 1000000007;
    const groups = new Map();
    const rev = x => parseInt(String(x).split('').reverse().join(''), 10);
    let ans = 0;
    for (const x of nums) {
        const key = x - rev(x);
        const c = groups.get(key) || 0;
        ans = (ans + c) % MOD;
        groups.set(key, c + 1);
    }
    return ans;
};
